// Helper functions
func monthName(year, month int) string {
	return fmt.Sprintf("%s %d", time.Month(month).String(), year)
}

func monthBack(year, month int) struct{ Year, Month int } {
	m := month - 1
	y := year
	if m < 1 {
		m = 12
		y--
	}
	return struct{ Year, Month int }{y, m}
}

func monthForward(year, month int) struct{ Year, Month int } {
	m := month + 1
	y := year
	if m > 12 {
		m = 1
		y++
	}
	return struct{ Year, Month int }{y, m}
}

